queries.sparql:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?feature_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFeatures ?child ; p:hasCommunities ?parent . } GROUP BY ?child }
  ?child p:feature_value ?feature_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Communities } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?feature_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFeatures ?child ; p:hasCommunities ?parent . } GROUP BY ?child }
  ?child p:feature_value ?feature_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Communities } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?community_name ?feature_value WHERE {
  ?communities_features a :Communities_Features .
  ?features a :Features .
  ?communities_features p:hasFeatures ?features .
  ?communities a :Communities .
  ?communities_features p:hasCommunities ?communities .
  ?communities p:community_name ?community_name .
  ?features p:feature_value ?feature_value .
} }
}
